namespace sv_cd08bf31a303406498b405c6d1156d33.Services;

/// <summary>
/// Scoped service that manages low-stock alert polling for a single user circuit.
/// Polls every 10 seconds when active, notifies all subscribers when new data arrives.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;

    public int CurrentLowStockCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChanged;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Starts polling. Uses reference counting so multiple subscribers
    /// share one timer. Polling stops when all subscribers unsubscribe.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(_cts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            CancelTimer();
        }
    }

    /// <summary>
    /// Fetches alert count immediately and notifies all subscribers.
    /// Called when warehouse changes to get fresh data right away.
    /// </summary>
    public async Task RefreshAsync()
    {
        CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        OnAlertCountChanged?.Invoke();
    }

    private async Task PollLoopAsync(CancellationToken cancellationToken)
    {
        // Fetch immediately on start
        await RefreshAsync();

        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                if (_timer is null || !await _timer.WaitForNextTickAsync(cancellationToken))
                    break;

                CurrentLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
                OnAlertCountChanged?.Invoke();
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    private void HandleWarehouseChanged()
    {
        if (_subscriberCount > 0)
        {
            _ = RefreshAsync();
        }
    }

    private void CancelTimer()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChanged;
        CancelTimer();
    }
}

