@page "/dashboard"
@rendermode InteractiveServer
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Currently viewing: <strong>@CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <span class="display-4 text-danger">@AlertService.CurrentLowStockCount</span>
                <p class="text-muted mt-2">items below minimum level</p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Warehouse ID</h5>
                <span class="display-6">@WarehouseState.CurrentWarehouseId</span>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <span class="badge bg-success fs-6">Active</span>
                <p class="text-muted mt-2">Refreshes every 10s</p>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    private string CurrentWarehouseName =>
        WarehouseState.AvailableWarehouses
            .FirstOrDefault(w => w.Id == WarehouseState.CurrentWarehouseId)?.Name
        ?? "Unknown";

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling when dashboard becomes visible
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when user leaves the page
        AlertService.StopPolling();

        if (_warehouseHandler is not null)
            WarehouseState.OnChange -= _warehouseHandler;
        if (_alertHandler is not null)
            AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

